queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?photographers a :Photographers .
    ?photographers p:photographerName ?photographername .
    ?photographers p:price ?price_f .
    FILTER((STR(?price_f) = "500" || STR(?price_f) = "500.0"))
    BIND(?photographername AS ?o0)
  }
  UNION
  {
    ?videographers a :Videographers .
    ?videographers p:videographerName ?videographername .
    ?videographers p:price ?price_f .
    FILTER((STR(?price_f) = "500" || STR(?price_f) = "500.0"))
    BIND(?videographername AS ?o0)
  }
}

